section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/design-system-governance.json",
  "title": "Design System Governance",
  "type": "object",
  "required": [
    "artefact_id",
    "system_id",
    "owners",
    "rfc_pipeline",
    "contribution_rules",
    "deprecation_policy_ref",
    "breaking_change_policy_ref",
    "review_cadence",
    "escalation_path",
    "evidence",
    "status",
    "owner",
    "last_touched",
    "template_version"
  ],
  "properties": {
    "artefact_id": {
      "type": "string",
      "description": "slug + ISO date or UUID",
      "minLength": 1
    },
    "system_id": {
      "type": "string",
      "description": "system_id",
      "minLength": 1
    },
    "owners": {
      "type": "string",
      "description": "owners",
      "minLength": 1
    },
    "rfc_pipeline": {
      "type": "string",
      "description": "rfc_pipeline",
      "minLength": 1
    },
    "contribution_rules": {
      "type": "array",
      "description": "contribution_rules (array)",
      "minItems": 1
    },
    "deprecation_policy_ref": {
      "type": "string",
      "description": "deprecation_policy_ref",
      "minLength": 1
    },
    "breaking_change_policy_ref": {
      "type": "string",
      "description": "breaking_change_policy_ref",
      "minLength": 1
    },
    "review_cadence": {
      "type": "string",
      "description": "review_cadence",
      "minLength": 1
    },
    "escalation_path": {
      "type": "string",
      "description": "escalation_path",
      "minLength": 1
    },
    "evidence": {
      "type": "array",
      "description": "{source, citation} pairs anchoring non-trivial fields",
      "minItems": 1
    },
    "status": {
      "type": "string",
      "description": "draft|ready_for_review|approved|archived",
      "minLength": 1
    },
    "owner": {
      "type": "string",
      "description": "single named owner; generic group terms forbidden",
      "minLength": 1
    },
    "last_touched": {
      "type": "string",
      "description": "ISO-8601 timestamp",
      "format": "date-time"
    },
    "template_version": {
      "type": "string",
      "description": "semver matching methodology frontmatter at write time"
    }
  },
  "additionalProperties": false
}
